create extension if not exists pgcrypto;
create table public.circles(id uuid primary key default gen_random_uuid(),name text not null,context text not null,invite_code_hash text not null unique,created_at timestamptz not null default now());
create table public.circle_memberships(circle_id uuid references public.circles on delete cascade,user_id uuid references auth.users on delete cascade,role text not null check(role in('participant','curator')) default 'participant',joined_at timestamptz not null default now(),primary key(circle_id,user_id));
create table public.themes(id uuid primary key default gen_random_uuid(),circle_id uuid not null references public.circles on delete cascade,slug text not null,title text not null,subtitle text not null,is_active boolean not null default true,created_at timestamptz not null default now(),unique(circle_id,slug));
create table public.catalog_items(id uuid primary key default gen_random_uuid(),theme_id uuid not null references public.themes on delete cascade,kind text not null check(kind in('signal','group','consequence')),layer text check(layer in('tension','support','potential')),label text not null,sort_order int not null default 0,is_active boolean not null default true,unique(theme_id,kind,layer,label));
create table public.contributions(id uuid primary key default gen_random_uuid(),circle_id uuid not null references public.circles on delete cascade,theme_id uuid not null references public.themes on delete cascade,user_id uuid not null references auth.users on delete cascade,layer text not null check(layer in('tension','support','potential')),signal_id uuid not null references public.catalog_items,group_id uuid not null references public.catalog_items,consequence_id uuid not null references public.catalog_items,evidence text not null check(evidence in('experienced','observed')),intensity text not null check(intensity in('low','medium','high')),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(circle_id,theme_id,user_id,layer,signal_id,group_id,consequence_id));
create table public.candidate_proposals(id uuid primary key default gen_random_uuid(),circle_id uuid not null references public.circles on delete cascade,theme_id uuid not null references public.themes on delete cascade,author_id uuid not null references auth.users on delete cascade,layer text not null check(layer in('tension','support','potential')),proposal_kind text not null check(proposal_kind in('signal','consequence')),raw_text text not null check(char_length(trim(raw_text)) between 1 and 80),status text not null check(status in('pending','approved','rejected')) default 'pending',curator_note text,created_at timestamptz not null default now(),reviewed_at timestamptz,reviewed_by uuid references auth.users);
create index on public.circle_memberships(user_id); create index on public.themes(circle_id); create index on public.catalog_items(theme_id,kind,layer); create index on public.contributions(theme_id,layer,signal_id,consequence_id); create index on public.candidate_proposals(circle_id,status);
alter table public.circles enable row level security; alter table public.circle_memberships enable row level security; alter table public.themes enable row level security; alter table public.catalog_items enable row level security; alter table public.contributions enable row level security; alter table public.candidate_proposals enable row level security;
create or replace function public.is_member(input_circle uuid) returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.circle_memberships m where m.circle_id=input_circle and m.user_id=auth.uid())$$;
create or replace function public.is_curator(input_circle uuid) returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.circle_memberships m where m.circle_id=input_circle and m.user_id=auth.uid() and m.role='curator')$$;
create policy member_circles on public.circles for select using(public.is_member(id));
create policy own_membership on public.circle_memberships for select using(user_id=auth.uid() or public.is_curator(circle_id));
create policy member_themes on public.themes for select using(public.is_member(circle_id));
create policy member_catalog on public.catalog_items for select using(exists(select 1 from public.themes t where t.id=theme_id and public.is_member(t.circle_id)));
create policy own_contrib_select on public.contributions for select using(user_id=auth.uid());
create policy own_contrib_insert on public.contributions for insert with check(user_id=auth.uid() and public.is_member(circle_id));
create policy own_contrib_update on public.contributions for update using(user_id=auth.uid()) with check(user_id=auth.uid());
create policy proposal_select on public.candidate_proposals for select using(author_id=auth.uid() or public.is_curator(circle_id));
create policy proposal_insert on public.candidate_proposals for insert with check(author_id=auth.uid() and public.is_member(circle_id));
create policy curator_update_proposals on public.candidate_proposals for update using(public.is_curator(circle_id)) with check(public.is_curator(circle_id));
create or replace function public.join_circle_by_code(input_code text) returns table(circle_id uuid,circle_name text,circle_context text) language plpgsql security definer set search_path='' as $$declare found public.circles%rowtype; begin if auth.uid() is null then raise exception 'not authenticated'; end if; select * into found from public.circles c where c.invite_code_hash=encode(digest(upper(trim(input_code)),'sha256'),'hex') limit 1; if found.id is null then return; end if; insert into public.circle_memberships(circle_id,user_id) values(found.id,auth.uid()) on conflict do nothing; return query select found.id,found.name,found.context; end;$$;
create or replace function public.upsert_contribution(input_theme_id uuid,input_layer text,input_signal_id uuid,input_group_id uuid,input_consequence_id uuid,input_evidence text,input_intensity text) returns uuid language plpgsql security definer set search_path='' as $$declare c_id uuid; out_id uuid; begin select circle_id into c_id from public.themes where id=input_theme_id; if c_id is null or not public.is_member(c_id) then raise exception 'not allowed'; end if; insert into public.contributions(circle_id,theme_id,user_id,layer,signal_id,group_id,consequence_id,evidence,intensity) values(c_id,input_theme_id,auth.uid(),input_layer,input_signal_id,input_group_id,input_consequence_id,input_evidence,input_intensity) on conflict(circle_id,theme_id,user_id,layer,signal_id,group_id,consequence_id) do update set evidence=excluded.evidence,intensity=excluded.intensity,updated_at=now() returning id into out_id; return out_id; end;$$;
create or replace function public.get_theme_snapshot(input_theme_id uuid) returns jsonb language sql stable security definer set search_path='' as $$with allowed as (select t.circle_id from public.themes t where t.id=input_theme_id and public.is_member(t.circle_id)), rows as (select c.* from public.contributions c, allowed where c.theme_id=input_theme_id), branch as (select layer,signal_id,group_id,consequence_id,count(distinct user_id) participants,count(distinct group_id) distinct_groups,count(distinct evidence) evidence_types,sum((case evidence when 'experienced' then 1.0 else 0.6 end)*(case intensity when 'low' then .75 when 'medium' then 1.0 else 1.35 end)*exp(-ln(2)*greatest(0,extract(epoch from now()-updated_at)/86400)/21)) effective from rows group by 1,2,3,4), enriched as (select *,ln(1+effective)*(1+least(.30,.08*(distinct_groups-1))) strength,least(1,.18*sqrt(participants)+.14*sqrt(distinct_groups)+.10*(case when evidence_types>1 then 1 else .5 end)) clarity from branch) select jsonb_build_object('participantCount',(select count(distinct user_id) from rows),'threadCount',(select count(*) from rows),'branches',coalesce(jsonb_agg(jsonb_build_object('layer',layer,'signalId',signal_id,'groupId',group_id,'consequenceId',consequence_id,'participantCount',participants,'distinctGroups',distinct_groups,'evidenceDiversity',case when evidence_types>1 then 1 else .5 end,'strength',strength,'clarity',clarity,'status',case when clarity<.35 then 'fog' when clarity<.65 then 'emerging' else 'confirmed' end)),'[]'::jsonb)) from enriched;$$;
revoke all on function public.join_circle_by_code(text) from public; revoke all on function public.get_theme_snapshot(uuid) from public; revoke all on function public.upsert_contribution(uuid,text,uuid,uuid,uuid,text,text) from public; grant execute on function public.join_circle_by_code(text), public.get_theme_snapshot(uuid), public.upsert_contribution(uuid,text,uuid,uuid,uuid,text,text) to authenticated;
